sql:
SELECT station_name, total_rides
FROM stations
ORDER BY total_rides DESC;

external_knowledge:
- The term 'top three travelers' refers to the individuals who have taken the highest number of trips; 
- The `trips` table records each trip made by users;
- The `users` table contains the identities of the users, including their IDs and names.

sql:
SELECT AVG(JULIANDAY('now') - JULIANDAY(last_maintenance_date)) AS average_days_since_last_maintenance
FROM bike_status
WHERE bike_status = 'in use';

SELECT DISTINCT trips.user_id, user_feedback.feedback_text
FROM trips
INNER JOIN user_feedback ON trips.user_id = user_feedback.user_id;
